action.action:
#Remove theme
if [[ '%remove_theme%' = '1' ]] || [[ '%theme_style_tmp%' = 'Cream' && '%theme_accent_tmp%' = 'Orange' && '%theme_font_tmp%' = 'Roboto' && '%theme_sec_font_tmp%' = 'GoogleSans' && '%theme_font_size_tmp%' = 'n' ]]; then
	[ -d "%fox_theme_path%" ] && rm -rf %fox_theme_path%;
	[[ '%update_navbar%' = '1' ]] || exit;
else
	if [ ! -d "%fox_theme_path%" ]; then mkdir -p -m 0755 "%fox_theme_path%"; chcon -R "%fox_media_rw_data_file%" "%fox_theme_path%"; chown -R "%fox_media_rw%" "%fox_theme_path%"; fi;
fi;

#Fonts
if [[ '%update_fonts%' = '1' ]]; then
	medfont=Medium;
	regfont=Regular;

	[[ '%theme_font_weight_tmp%' = '1' ]] && medfont=Regular;
	[[ '%theme_font_weight_tmp%' = '2' ]] && regfont=Medium;

	if [ -f "/twres/fonts/%theme_sec_font_tmp%.ttf" ];
		then sec_med=;
			 sec_reg=;
		else sec_med=-${medfont};
			 sec_reg=-${regfont};
	fi;
	if [ -f "/twres/fonts/%theme_font_tmp%.ttf" ];
		then prim_med=;
			 prim_reg=;
		else prim_med=-${medfont};
			 prim_reg=-${regfont};
	fi;
	cat "/twres/themes/sed/font_%theme_font_size_tmp%.xml" | sed -e "
	s/#WEIGHT#/%theme_font_weight_tmp%/g;
	s/#PRIMARY_FONT_MED#/%theme_font_tmp%${prim_med}/g;
	s/#PRIMARY_FONT_REG#/%theme_font_tmp%${prim_reg}/g;
	s/#SECONDARY_FONT_MED#/%theme_sec_font_tmp%${sec_med}/g;
	s/#SECONDARY_FONT_REG#/%theme_sec_font_tmp%${sec_reg}/g;
	s/#PRIMARY_NAME#/%theme_font_tmp%/g;
	s/#SECONDARY_NAME#/%theme_sec_font_tmp%/g
	" > %fox_theme_path%/font.xml;
fi;

#Navbar
if [[ '%update_navbar%' = '1' ]]; then
	if [ ! -d "%fox_navbar_path%" ]; then mkdir -p -m 0755 "%fox_navbar_path%"; chcon -R "%fox_media_rw_data_file%" "%fox_navbar_path%"; chown -R "%fox_media_rw%" "%fox_navbar_path%"; fi;
	navbar_disable_add='%navbar_disable_add_tmp%';
	if [ -z "${navbar_disable_add}" ]; then
		echo "E: navbar_disable_add_tmp is empty; aborting navbar regeneration." >> /tmp/recovery.log;
		exit 1;
	fi;
	if ! screen_h=$(expr %screen_original_h% + "${navbar_disable_add}"); then
		echo "E: Failed to compute navbar screen_h; aborting navbar regeneration." >> /tmp/recovery.log;
		exit 1;
	fi;
	if [ -z "${screen_h}" ]; then
		echo "E: Computed navbar screen_h is empty; aborting navbar regeneration." >> /tmp/recovery.log;
		exit 1;
	fi;
	cat "/twres/themes/sed/navbar.xml" | sed -e "
	s/#NAVBAR_DISABLE#/%navbar_disable_tmp%/g;
	s/#NAVBAR_DISABLE_ADD#/${navbar_disable_add}/g;
	s/#RGE#/%real_gestures_enable_tmp%/g;
	s/#SCREEN_H#/${screen_h}/g
	" > %fox_navbar_path%/navbar.xml;
	chcon -R "%fox_media_rw_data_file%" "%fox_navbar_path%/navbar.xml";
	chown -R "%fox_media_rw%" "%fox_navbar_path%/navbar.xml";
fi;

#Style
if [[ '%update_style%' = '1' ]]; then
	cat "/twres/themes/styles/%theme_style_tmp%.xml" > %fox_theme_path%/style.xml;
	chcon -R "%fox_media_rw_data_file%" "%fox_theme_path%/style.xml";
	chown -R "%fox_media_rw%" "%fox_theme_path%/style.xml";
fi;

#Accent
if [[ '%update_accent%' = '1' ]] || [[ '%update_style%' = '1' ]]; then
	if [[ '%theme_style_act_tmp%' = 'Default' ]]; then
		cat "/twres/themes/sed/accent.xml" | sed -e "
		s/#ACCENT_NAME#/%theme_accent_tmp%/g;
		s/#COLOR#/%theme_accent_dark_tmp%/g;
		s/#COLOR_LIGHT#/%theme_accent_light_tmp%/g;
		s/#COLOR_DARK#/%theme_accent_dark_tmp%/g
		" > %fox_theme_path%/accent.xml;
		chcon -R "%fox_media_rw_data_file%" "%fox_theme_path%/accent.xml";
		chown -R "%fox_media_rw%" "%fox_theme_path%/accent.xml";
	else
		cat "/twres/themes/sed/accent.xml" | sed -e "
		s/#ACCENT_NAME#/%theme_accent_tmp%/g;
		s/#COLOR#/%theme_accent_light_tmp%/g;
		s/#COLOR_LIGHT#/%theme_accent_light_tmp%/g;
		s/#COLOR_DARK#/%theme_accent_dark_tmp%/g
		" > %fox_theme_path%/accent.xml;
		chcon -R "%fox_media_rw_data_file%" "%fox_theme_path%/accent.xml";
		chown -R "%fox_media_rw%" "%fox_theme_path%/accent.xml";
	fi;
fi;

if [[ '%spl_bg_user%' = '1' ]]; then
	[[ '%spl_logo_type%' = 'o' ]] && logo_color=F86314;
	[[ '%spl_logo_type%' = 'w' ]] && logo_color=ffffff;
	[[ '%spl_logo_type%' = 'd' ]] && logo_color=353535;

	if [[ '%spl_logo_type%' = '0' ]];
		then logo_on=!--;
		else logo_on=;
	fi;
	if [[ '%spl_ofr%' = '1' ]];
		then logo_ofr=;
		else logo_ofr=!--;
	fi;

	[[ '%spl_logo_type%' = '0' ]] && logo_ofr=!--;

	if [[ '%spl_bg_on%' = '1' ]] && [[ "$(du -s "%tw_splash_png_path%/%tw_splash_png_name%" | cut -f1)" -lt "%of_splash_max_size%" ]];
			then bg_on=;
				cp "%tw_splash_png_path%/%tw_splash_png_name%" "/tmp/orangefox/ramdisk/twres/images/Splash/user.png";
				cp "%tw_splash_png_path%/%tw_splash_png_name%" "/twres/images/Splash/user.png";
			else bg_on=!--;
				cp "/twres/images/Splash/empty.png" "/tmp/orangefox/ramdisk/twres/images/Splash/user.png";
				cp "/twres/images/Splash/empty.png" "/twres/images/Splash/user.png";
				if [[ '%spl_bg_on%' = '1' ]] && [[ "$(du -s "%tw_splash_png_path%/%tw_splash_png_name%" | cut -f1)" -gt "%of_splash_max_size%" ]];
				   then echo "I:The splash image must not be bigger than %of_splash_max_size% Kb. The splash image will not be changed." >> /tmp/recovery.log;
				fi;
	fi;
	cat "/twres/themes/sed/splash.xml" | sed -e "
	s/#SHOWOFR#/${logo_ofr}/g;
	s/#TCOLOR#/${logo_color}/g;
	s/#BG_COLOR#/%spl_bg_color%/g;
	s/#LOGO_TYPE#/%spl_logo_type%/g;
	s/#LOGO_ON#/${logo_on}/g;
	s/#BG_IMG#/${bg_on}/g
	" > /tmp/orangefox/ramdisk/twres/splash.xml;
else
	cat "/twres/themes/sed/splash_orig.xml" > /tmp/orangefox/ramdisk/twres/splash.xml;
fi;
cat "/tmp/orangefox/ramdisk/twres/splash.xml" > /twres/splash.xml;
twrp xset spl_parsed=0;

splash=/twres/splash.xml;
spl_logo_string=`cat $splash | grep 'image name="splash_logo"'`;
spl_bg_user_string=`cat $splash | grep 'image name="splash_bg"'`;
spl_bg_color_string=`cat $splash | grep 'background color='`;
spl_text_string=`cat $splash | grep 'text style='`;

echo ${spl_logo_string} | grep '!--' > /dev/null;
if [ $? -ne 0 ]; then
	spl_logo_type=`echo ${spl_logo_string} | sed 's/.*\/logo_\(.\).*/\1/'`;
fi;

echo ${spl_bg_user_string} | grep '!--' > /dev/null;
if [ $? -ne 0 ]; then
	twrp xset spl_bg_on=1;
fi;

echo ${spl_bg_color_string} | grep '!--' > /dev/null;
if [ $? -ne 0 ]; then
	spl_bg_color=`echo ${spl_bg_color_string} | sed 's/.*color="\([^"]*\)".*/\1/'`;
fi;

echo ${spl_text_string} | grep '!--' > /dev/null;
if [ $? -ne 0 ]; then
	twrp xset spl_ofr=1;
fi;

if [[ ! -z ${spl_logo_type} ]]; then
	twrp xset spl_logo_type=${spl_logo_type};
	twrp xset spl_bg_user=1;
fi;

if [[ ! -z ${spl_bg_color} ]]; then
	twrp xset spl_bg_color=${spl_bg_color};
	twrp xset spl_bg_user=1;
fi;

cat $splash | grep "SED Splash";
if [ $? -ne 0 ]; then
	twrp xset spl_bg_user=0;
	twrp xset spl_bg_on=0;
fi;

twrp xset spl_parsed=1;

exit 0;
